-- Seed: sports catalog, WC2026 league, venues, competitors, fixtures. Idempotent.
insert into public.sports (key, name) values
  ('soccer', 'Soccer'), ('motorsport', 'Motorsport'), ('hockey', 'Hockey'),
  ('basketball', 'Basketball'), ('tennis', 'Tennis'), ('golf', 'Golf'),
  ('mma', 'MMA'), ('american_football', 'American football'), ('custom', 'Community')
on conflict (key) do nothing;

insert into public.leagues (sport_id, provider_key, provider_league_id, name, short_name, country)
select s.id, league.provider_key, league.provider_league_id, league.name, league.short_name, league.country
from public.sports s
join (
  values
    ('motorsport', 'catalog', 'f1', 'Formula 1', 'F1', null),
    ('hockey', 'catalog', 'nhl', 'National Hockey League', 'NHL', 'US/CA'),
    ('basketball', 'catalog', 'nba', 'National Basketball Association', 'NBA', 'US/CA'),
    ('basketball', 'catalog', 'wnba', 'Women''s National Basketball Association', 'WNBA', 'US'),
    ('mma', 'catalog', 'ufc', 'Ultimate Fighting Championship', 'UFC', null),
    ('mma', 'catalog', 'pfl', 'Professional Fighters League', 'PFL', null),
    ('american_football', 'catalog', 'cfl', 'Canadian Football League', 'CFL', 'CA')
) as league(sport_key, provider_key, provider_league_id, name, short_name, country)
  on s.key = league.sport_key
on conflict (provider_key, provider_league_id) do nothing;

insert into public.leagues (sport_id, provider_key, provider_league_id, name, short_name)
select s.id, 'worldcup_json', 'wc2026', 'FIFA World Cup 2026', 'WC 2026'
from public.sports s where s.key = 'soccer'
on conflict (provider_key, provider_league_id) do nothing;

